import{c as d,a,b as t,w as s,u as i,R as o,d as n,o as l,k as r}from"./vue-vendor-ZcKwQDbZ.js";import{u as c}from"./useRouteSEO-2vv39j6j.js";import{_ as u}from"./index-BgV7_-Ev.js";const h={class:"post-view"},p={class:"mv-container"},m={class:"post-grid"},g={class:"post-content"},f={class:"post-sidebar"},v={class:"sidebar-card"},y={class:"sidebar-nav"},b={class:"sidebar-card"},w={__name:"EducationPostView",setup(k){return c(),(_,e)=>(l(),d("div",h,[a("div",p,[a("div",m,[a("article",g,[t(i(o),{to:"/education",class:"post-back"},{default:s(()=>[...e[0]||(e[0]=[r("← Back to Education",-1)])]),_:1}),e[1]||(e[1]=n('<span class="mv-section-label" data-v-03985dc4>Emerald Education</span><h1 data-v-03985dc4>The 4 Cs of Emeralds: What Actually Matters</h1><p class="post-meta" data-v-03985dc4>Published March 2024 · 5 min read</p><div class="post-body" data-v-03985dc4><p data-v-03985dc4> When most people learn about the 4 Cs — Color, Clarity, Cut, and Carat — they apply what they know from diamond grading. That&#39;s a mistake. Emeralds are graded differently, and understanding those differences is essential to making a smart purchase. </p><h2 data-v-03985dc4>Color</h2><p data-v-03985dc4> Colombian emeralds are prized for their &quot;vertically oriented&quot; color — a rich, vivid green with a slight blue modifier. The finest specimens display what gemologists call &quot;Muzo green,&quot; named after the legendary mine in Boyacá, Colombia. </p><p data-v-03985dc4> Unlike diamonds where color is about absence of color, emeralds are valued for the intensity and purity of their green. Hue, tone, and saturation all matter. A stone that&#39;s too dark loses brilliance; too light and it reads as greenish beryl, not emerald. </p><h2 data-v-03985dc4>Clarity</h2><p data-v-03985dc4> Emeralds are TYPE III gemstones — meaning they virtually always have inclusions. This is expected and accepted. The key is understanding what&#39;s inside and whether it affects durability or appearance. </p><p data-v-03985dc4> GIA grades emerald clarity using a scale that accounts for the stone&#39;s natural &quot;jardin&quot; (garden), the characteristic inclusion pattern that looks like foliage. Looking for an &quot;eye-clean&quot; emerald in the traditional sense is unrealistic and often leads to buying treated stones masquerading as natural. </p><h2 data-v-03985dc4>Cut</h2><p data-v-03985dc4> Emeralds are cut to maximize color retention and weight retention from the rough. The classic emerald cut — an octagonal step cut — was developed specifically for this gem type to minimize pressure during setting and showcase the color while hiding inclusions. </p><p data-v-03985dc4> Other cuts exist (oval, cushion, pear), but the priority is preserving the stone&#39;s integrity, not maximizing brilliance. A poorly cut emerald will appear dull regardless of its color grade. </p><h2 data-v-03985dc4>Carat</h2><p data-v-03985dc4> Emeralds are less dense than diamonds, so a 1-carat emerald is larger than a 1-carat diamond. Weight translates differently. But the real story is that fine emeralds over 2 carats are exponentially rarer — and more valuable — than their lower-weight counterparts. </p></div>',4))]),a("aside",f,[a("div",v,[e[5]||(e[5]=a("h4",null,"Related Articles",-1)),a("nav",y,[t(i(o),{to:"/education/origin-matters",class:"sidebar-link"},{default:s(()=>[...e[2]||(e[2]=[r("Why Colombian Origin Matters",-1)])]),_:1}),t(i(o),{to:"/education/oil-treatments",class:"sidebar-link"},{default:s(()=>[...e[3]||(e[3]=[r("Oil, Resin & Fracture Filling",-1)])]),_:1}),t(i(o),{to:"/tools/certification-decoder",class:"sidebar-link"},{default:s(()=>[...e[4]||(e[4]=[r("Decode Any GIA Certificate",-1)])]),_:1})])]),a("div",b,[e[7]||(e[7]=a("h4",null,"Ready to find your stone?",-1)),t(i(o),{to:"/quiz",class:"mv-btn-primary",style:{width:"100%","text-align":"center"}},{default:s(()=>[...e[6]||(e[6]=[r("Take the Quiz",-1)])]),_:1})])])])])]))}},q=u(w,[["__scopeId","data-v-03985dc4"]]);export